var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"첫 번째 공세는 실패! 이미 두 명이나 리타이어 당한 카나리아 스쿼드─!","JPN":"最初の攻撃は失敗！　すでに二人もリタイアしてしまったカナリア・スクワッド─！","ENG":"First attack ended in failure! And Canary Squad has already lost 2 of their members!","TWN":"第一次進攻失敗！金絲雀小隊已經有二個人遭到淘汰—！"},"stage":{"bg":"CCN_SHIP","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"노엘의 분전으로 꽁무니는 뺐지만, 챔피언은 쉽게 도주를 허용하지 않는다구!","JPN":"ノエルが奮闘したおかげで逃げられましたが、チャンピオンはそう簡単に逃がしてくれないぞ！","ENG":"They were able to flee thanks to Noelle's sacrifice, but the champion isn't allowing them to escape so easily!","TWN":"在洛艾兒的奮戰之下，雖然得以脫身，但冠軍不會輕易容許他們逃掉的！"},"stage":{"bg":"CCN_SHIP","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"연이어 터지는 피격 판정! 앞으로 수차례면 격추 판정까지 다다르는 상황!","JPN":"どんどん溜まっていくダメージ判定！　あと数回溜まれば撃墜判定になっちゃう！","ENG":"Canary's aircraft is on its last wings! Just a few more hits, and it'll be determined as shot down!","TWN":"接連被判定為擊中！再來幾次的話，就會達到擊落判定！"},"stage":{"bg":"CCN_SHIP","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"그렇다고 경기 구역을 이탈하면 즉시 패배 판정이니까 조심해야 할 걸?","JPN":"でも、試合エリアを離れてしまったらその場で負けになるから、気を付けないとね？","ENG":"But be careful not to go out of bounds or it'll be immediate defeat!","TWN":"但如果因此脫離賽區，就會立刻被判定失敗，所以要小心囉？"},"stage":{"bg":"CCN_SHIP","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"카나리아 스쿼드! 절체절명의 위기!","JPN":"カナリア・スクワッド！　絶体絶命の危機！","ENG":"Canary Squad's in a moment of crisis!","TWN":"金絲雀小隊！千鈞一髮的危機！"},"stage":{"bg":"CCN_SHIP","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"하지만 어떻게 여기까지 왔는데! 쉽게 포기하면 안 되지!","JPN":"しかしやっとここまで来たのに、諦めるわけにはいかないよね！","ENG":"But they made it so far! You can't give up that easily!","TWN":"但好不容易走到這一步！不能輕言放棄！"},"stage":{"bg":"CCN_SHIP","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"제한 시간까지 아직 한 번 더 역전할 찬스가 남아 있어!","JPN":"制限時間まであともう一回だけ逆転するチャンスはある！","ENG":"There's still enough time to make a turnaround!","TWN":"在比賽結束前還有一次可以反敗為勝的機會！"},"stage":{"bg":"PROLOGUE_03","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"마지막까지 최선을 다해! 널 응원하는 사람들을 실망시킬 셈이냐?!","JPN":"最後まで全力を出し切って！　あなたを応援してくれる人たちをがっかりさせるんじゃないよ！","ENG":"Give it your best until the end! You can't disappoint all the fans cheering you on!","TWN":"要盡全力拚到最後！你是想讓為你加油的人失望嗎？！"},"stage":{"bg":"PROLOGUE_03","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PROLOGUE_03","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"격추 판정까지 앞으로 3회……!","JPN":"撃墜判定まであと3回……！","ENG":"3 more hits until the ship goes down!","TWN":"距離被判定為擊落還有3次……！"},"stage":{"bg":"PROLOGUE_03","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"위험해. 이대로 수송선에 탑승한 상태로 격추 판정이 뜨면, 우리 전원 리타이어라고.","JPN":"まずいわ。このまま輸送船に乗った状態で撃墜判定になったら、私たち全員がリタイアになっちゃう。","ENG":"This isn't looking good. If our ship goes down with all of us in it, we're all out.","TWN":"太危險了，要是在大家搭乘運輸機的狀態下被判定為擊落，那我們全部都會遭到淘汰的。"},"stage":{"bg":"PROLOGUE_03","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"펠리세트! 일단 적당한 엄폐물 뒤에 내려 줄게!","JPN":"フェリセット！　とりあえず適当に隠れられそうな場所に降ろすわよ！","ENG":"Félicette! I'll drop you off behind some cover for now!","TWN":"費莉塞特！我先把你放在可以掩護你的遮蔽物後面！"},"stage":{"bg":"PROLOGUE_03","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"……","JPN":"……","ENG":"……","TWN":"……"},"stage":{"bg":"PROLOGUE_03","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":null,"text":{"KOREA":"듣고 있나, 펠리세트?","JPN":"聞こえるか、フェリセット？","ENG":"Can you hear me, Félicette?","TWN":"你有聽到嗎，費莉塞特？"},"stage":{"bg":"PROLOGUE_03","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"듣고 있어요, 코치.","JPN":"聞いています、コーチ。","ENG":"I'm listening, Coach.","TWN":"有聽到，教練。"},"stage":{"bg":"PROLOGUE_03","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"라이카 양과 로이 군은 어떤가?","JPN":"ライカ君とロイ君の調子はどうだ？","ENG":"How's Laika and Roy?","TWN":"萊卡和羅伊情況如何？"},"stage":{"bg":"PROLOGUE_03","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"라이카는 의식을 회복해서 휴식 중이고…….","JPN":"ライカは意識を取り戻して、今休んでいて……","ENG":"Laika's regained her consciousness and resting...","TWN":"萊卡已經恢復意識，正在休息中……"},"stage":{"bg":"PROLOGUE_03","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"로이 씨는 수송선에 탈 때 사슬검에 다리를 맞았어요.","JPN":"ロイさんは輸送船に乗り込むときに蛇腹剣で脚をやられました。","ENG":"But Roy got his leg injured by her whip sword while jumping onto the ship.","TWN":"羅伊要上運輸機時剛好被鏈劍打中腿。"},"stage":{"bg":"PROLOGUE_03","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"가까스로 쇠사슬을 걸쳐서 추락은 면했지만, 부상으로 움직일 수 없으니 리타이어겠죠.","JPN":"ギリギリ鎖をひっかけて墜落は免れましたが、負傷で動けないので、リタイアになりますね。","ENG":"He managed to avoid falling by linking his chain to the ship at the last second, but he can't move due to his injury, so I guess he's out.","TWN":"幸好被鐵鍊勾住不至於墜機，但他現在因為受傷而動彈不得，所以應該算是淘汰。"},"stage":{"bg":"PROLOGUE_03","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"그리고 노엘은…….","JPN":"それからノエルは……","ENG":"And for Noelle...","TWN":"還有洛艾兒……"},"stage":{"bg":"PROLOGUE_03","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PROLOGUE_03","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"이제 다 끝났어요. 저희의 패배예요.","JPN":"もうダメです。私たちの負けです。","ENG":"It's all over. We lost.","TWN":"都結束了，我們輸了。"},"stage":{"bg":"PROLOGUE_03","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"죄송해요. 이기겠다고 큰소리 뻥뻥 쳐놓고 꼴사납네요.","JPN":"すみません。勝つなんて大口叩いておいて、みっともないですね。","ENG":"I'm sorry. I'm so embarrassed after boasting about beating her.","TWN":"對不起，我之前還大言不慚地說絕對會贏，現在卻這麼狼狽。"},"stage":{"bg":"PROLOGUE_03","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"아직 경기는 끝나지 않았어.","JPN":"まだ試合は終わってない。","ENG":"The match isn't over yet.","TWN":"比賽還沒結束。"},"stage":{"bg":"PROLOGUE_03","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"포기하기에는 이르다고 생각하는데?","JPN":"諦めるには早いと思うが？","ENG":"Don't you think it's too early to give up?","TWN":"現在說放棄還言之過早。"},"stage":{"bg":"PROLOGUE_03","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PROLOGUE_03","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"다 보고 계셨으면서 무슨 뚱딴지 같은 소리를 하시는 거예요.","JPN":"全部見ていたくせに、空気も読めないんですか。","ENG":"You saw what happened. How can you even say that?","TWN":"教練不是也有看到，怎麼還說那些不切實際的話。"},"stage":{"bg":"PROLOGUE_03","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"제 힘으로는…… 오지만디아스한테 상처 하나 낼 수 없었어요.","JPN":"私の力じゃ……オジマンディアスに傷一つつけることすらできませんでした。","ENG":"With my strength... I couldn't even harm a hair on Ozymandias's head.","TWN":"靠我的力量……是無法傷到奧茲曼迪亞斯分毫的。"},"stage":{"bg":"PROLOGUE_03","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"오랫동안 이 순간만을 위해 살아왔는데…… 복수하겠다는 생각 하나로 버텨 온 건데…….","JPN":"ずっとこの瞬間のためだけに生きてきたのに……復讐のためだと思うことで耐えてきたのに……","ENG":"I've waited my whole life for this moment... Just to get revenge on her...","TWN":"一直以來我只為這一個瞬間而活……就靠著報仇的想法撐到現在……"},"stage":{"bg":"PROLOGUE_03","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"이럴 줄 알았으면…… 처음부터 아무것도 하지 말 걸 그랬어요.","JPN":"こうなるとわかってたら……最初から何もしなければよかったです。","ENG":"If I knew this would happen... I would've never even started it.","TWN":"早知如此……當初還不如什麼都別做。"},"stage":{"bg":"PROLOGUE_03","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"아니, 처음부터 이걸 손에 넣지 않았으면…… 복수할 엄두도 못 냈을 텐데…….","JPN":"ううん、最初からこんなもの手に入れなかったら……復讐しようなんて思うことすらしなかったのに……","ENG":"No, if I had never gotten this... then I would've never even thought about revenge...","TWN":"不，打從一開始這個東西就不該在我的手上……那我也不至於妄想要報仇……"},"stage":{"bg":"PROLOGUE_03","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"이제 더는……!","JPN":"でも、もう……！","ENG":"I just can't–!","TWN":"我再也……！"},"stage":{"bg":"PROLOGUE_03","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"예전부터 자네에게 한 가지 묻고 싶은 게 있었네.","JPN":"以前から君に一つ聞きたいと思っていたことがある。","ENG":"There's one thing I want to ask you for a long time.","TWN":"從很久以前我就想問你一個問題。"},"stage":{"bg":"PROLOGUE_03","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PROLOGUE_03","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"자네가 정말로 바라는 건……","JPN":"君が本当に望んでいるのは……","ENG":"What do you truly wish for?","TWN":"你真正的願望……"},"stage":{"bg":"PROLOGUE_03","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"복수인가?","JPN":"復讐か？","ENG":"Is it revenge?","TWN":"是報仇？"},"stage":{"bg":"PROLOGUE_03","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"승리인가?","JPN":"勝利か？","ENG":"Is it victory?","TWN":"還是勝利？"},"stage":{"bg":"PROLOGUE_03","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"……전에도 말씀드렸잖아요.","JPN":"……前も言いましたよね。","ENG":"...I've already told you this before.","TWN":"……我之前也跟你說過。"},"stage":{"bg":"PROLOGUE_03","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"오지만디아스를 죽여버릴 거라고.","JPN":"オジマンディアスを殺すことだって。","ENG":"I'm going to kill Ozymandias.","TWN":"我要殺了奧茲曼迪亞斯。"},"stage":{"bg":"PROLOGUE_03","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"아무리 생각해도 이상해서 말일세.","JPN":"何度考えてもおかしいと思うことがあってね。","ENG":"But it doesn't add up no matter how I look at it.","TWN":"但那句話我怎麼想都覺得奇怪。"},"stage":{"bg":"PROLOGUE_03","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그럼 자네는 왜 건틀렛이라는 수단을 택한 거지?","JPN":"では君はなぜ、ガントレットという手段を選んだんだ？","ENG":"Then why did you choose the Gauntlet as your means to an end?","TWN":"為什麼偏偏要選擇用聖鎧這個方法？"},"stage":{"bg":"PROLOGUE_03","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"정말로 챔피언을 죽이고 싶었다면, 다른 방법도 얼마든지 있었을 텐데.","JPN":"本当にチャンピオンを殺したいだけなら、他にいくらでも方法はあっただろうに。","ENG":"If you really wanted to kill the champion, I'm sure there were numerous alternatives.","TWN":"如果你真的想殺了冠軍，多的是其他的方法。"},"stage":{"bg":"PROLOGUE_03","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"무슨 말이 하고 싶으신 거예요?","JPN":"何が言いたいんですか？","ENG":"What are you trying to say?","TWN":"你想說什麼？"},"stage":{"bg":"PROLOGUE_03","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"이제와서 복수는 나쁜 거니까, 그만두라고 설교하는 거예요?","JPN":"今更復讐は悪だからやめろとでも説教するつもりですか？","ENG":"Are you trying to lecture me that revenge is bad and that I shouldn't do it? After all this?","TWN":"你是想對我說教，說報仇是不對的，要叫我收手嗎？"},"stage":{"bg":"PROLOGUE_03","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"아니, 그 반대야. 자네가 선택한 길은 틀리지 않았어.","JPN":"いや、その逆だ。君が選んだ道は間違っていない。","ENG":"No, it's quite the opposite. The path you chose is not wrong.","TWN":"不，正好相反。你選擇的路並沒有錯。"},"stage":{"bg":"PROLOGUE_03","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"다만, 복수의 대상을 착각하고 있을 뿐이지.","JPN":"ただし、復讐の対象を間違えているだけだ。","ENG":"However, I think you are mistaking the target of your vengeance.","TWN":"只是，你搞錯報仇的對象。"},"stage":{"bg":"PROLOGUE_03","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"복수의 대상이라고요?","JPN":"復讐の対象？","ENG":"Mistaking my target for vengeance?","TWN":"報仇的對象？"},"stage":{"bg":"PROLOGUE_03","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"나는 자네가 여기까지 오면서, 뭔가 느끼는 게 있을 거라고 생각했어.","JPN":"君がここまでたどり着く中で、何か気づいてくれると思った。","ENG":"I had thought you would feel something as you reached this point.","TWN":"我以為你一路走到這裡，應該有感受到什麼。"},"stage":{"bg":"PROLOGUE_03","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그래서 자네가 뭘 하고 싶은지 들은 뒤에도 계속 도와준 걸세.","JPN":"だからこそ君の目的を知った後も、協力し続けた。","ENG":"That is why I kept helping you even after hearing what you wanted to do.","TWN":"所以當我聽到你想做的事時，我依然選擇幫助你。"},"stage":{"bg":"PROLOGUE_03","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그러니 대답해 보게.","JPN":"その上で聞かせてくれ。","ENG":"So, answer this one question.","TWN":"所以，回答我。"},"stage":{"bg":"PROLOGUE_03","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"오지만디아스를 죽이지 못한 게 분한 건가?","JPN":"オジマンディアスを殺せなかったことが悔しいのか？","ENG":"Does your anger come from not having killed Ozymandias?","TWN":"讓你憤怒的，是因為沒能殺死奧茲曼迪亞斯嗎？"},"stage":{"bg":"PROLOGUE_03","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PROLOGUE_03","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"뭘 그렇게 시무룩한 표정이야, 꼬맹아.","JPN":"何をそんなに落ち込んでるんだよ、おこちゃま。","ENG":"What's with the long face, kid?","TWN":"小鬼，你臉幹嘛那麼臭。"},"stage":{"bg":"PROLOGUE_03","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"가자. 한 방 먹었으니까 두 방 먹여 주러 가야지.","JPN":"行こう。一発食らったからには二発で返さなきゃ。","ENG":"Let's go. She got us once, so it's time we paid her back twofold.","TWN":"走吧，既然挨了一記，當然要百倍奉還囉。"},"stage":{"bg":"PROLOGUE_03","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"라이카! 로이 씨! 두 사람 다 괜찮아요?","JPN":"ライカ！　ロイさん！　二人とも大丈夫なんですか？","ENG":"Laika! Roy! Are you both all right?","TWN":"萊卡！羅伊！你們二個都還好嗎？"},"stage":{"bg":"PROLOGUE_03","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"팔팔해! 실전이었으면 두 동강이 났겠지만.","JPN":"ぴんぴんしてるさ！　もし実戦だったら真っ二つだったと思うけど。","ENG":"Good as new! Though I'd be in two pieces if this wasn't a mock battle.","TWN":"生龍活虎的！幸好不是實戰，否則早就小命不保了吧。"},"stage":{"bg":"PROLOGUE_03","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"어이, 금발. 그러고보니 날 업고 수송기까지 뛰었다며?","JPN":"おい、金髪。そういえば私を背負って輸送船まで走ったんだってな？","ENG":"Hey, blonde hair. I heard you jumped onto the transport aircraft while carrying me.","TWN":"喂，金毛，聽說你把我揹上運輸機喔？"},"stage":{"bg":"PROLOGUE_03","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"혹시 응큼한 생각한 건 아니지? 난 댁 같이 비실비실한 애는 취향이 아니걸랑?","JPN":"ひょっとして下心があったわけじゃないよな？　私はおたくみたいなヒョロヒョロな男は好みじゃないよ？","ENG":"You weren't having pervy thoughts, were you? Just so you know, skinny guys like you aren't my type.","TWN":"你應該不是想對我做什麼邪惡的事吧？我可不喜歡你這種瘦皮猴。"},"stage":{"bg":"PROLOGUE_03","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"시끄러워. 기껏 다리까지 부러져 가면서 구해 놨더니 뭔 헛소리야.","JPN":"うるせえ。脚折れてるのを我慢して助けてやったのに、変なこと言うんじゃねえ。","ENG":"Shut up. I saved you while breaking a leg, and that's all you say to me?","TWN":"閉上你的嘴，我斷了一條腿還奮不顧身救你，你還在那說風涼話。"},"stage":{"bg":"PROLOGUE_03","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L37_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"꼬마 대장, 난 원래 지고는 못 살거든?","JPN":"チビ隊長。俺は負けることが絶対に許せないタイプなんだ。","ENG":"Little Captain, I'm not so good with defeats, okay?","TWN":"小不點隊長，我這人向來不服輸。"},"stage":{"bg":"PROLOGUE_03","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"마음 같아서는 당장이라도 그 챔피언한테 한 방 먹여주고 싶지만…….","JPN":"今すぐにでもあのチャンピオンに一発食らわせに行きたい気持ちはやまやまだが……","ENG":"I'd like to punch that champion in the face if I could, but...","TWN":"我是很想立刻就給冠軍還以顏色……"},"stage":{"bg":"PROLOGUE_03","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"아쉽게도 이번에는 못 갈 거 같다.","JPN":"残念ながら、今回は無理だ。","ENG":"Sadly, I don't think I can right now.","TWN":"只可惜我現在心有餘而力不足。"},"stage":{"bg":"PROLOGUE_03","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"……로이 씨.","JPN":"……ロイさん。","ENG":"...Roy.","TWN":"……羅伊。"},"stage":{"bg":"PROLOGUE_03","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"네가 챔피언이랑 무슨 관계든 그런 건 내 알 바 아니야.","JPN":"お前がチャンピオンとどういう関係だろうと、知ったこっちゃない。","ENG":"Your relationship with the champion is none of my business.","TWN":"無論你和冠軍是什麼關係，都不關我的事。"},"stage":{"bg":"PROLOGUE_03","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"그러니까 이겨. 반드시 이겨서 저 여자 낯짝이 일그러지는 걸 보여 주자고.","JPN":"だから勝て。必ず勝ってあの女の顔が歪むところを見ようぜ。","ENG":"But I want you to win. Win and show the world her ugly, defeated mug.","TWN":"你一定要贏，讓大家看看她的醜態。"},"stage":{"bg":"PROLOGUE_03","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PROLOGUE_03","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"아슬아슬하게 격추 판정을 피한 카나리아의 수송선! 그리고 수송선에서 내리는 건…….","JPN":"ギリギリで撃墜判定を免れたカナリアの輸送船！　そして輸送船から降りてくるのは……","ENG":"Canary Squad's aircraft barely avoided getting shot down! And it looks like someone's getting off...","TWN":"成功驚險避開擊落判定的金絲雀運輸機！從運輸機上下來的是……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"아─!! 라이카와 펠리세트─! 두 사람은 아직 포기하지 않았다─!!","JPN":"あ─！！　ライカとフェリセット─！　二人はまだ諦めていない─！！","ENG":"AH–! It's Laika and Félicette–! The duo haven't given up yet–!!","TWN":"哇—！是萊卡和費莉塞特—！她們二個人還沒有放棄—！！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"수송기는 이제 한계!! 팀에 카운터도 전멸했지만!!","JPN":"輸送船はもう限界！！　チームのカウンターも全滅！！","ENG":"Their ship's at its limits!! And all of their Counters are down!!","TWN":"運輸機已經到達極限！！不過隊上的制裁者也已經全軍覆沒！！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_HATE"},"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"옥상까지는 멀고!! 방어 측 병력은 아직 건재하지만!!","JPN":"屋上までは遠く！！　防御チームの戦力は全く減っていない状況だけど！！","ENG":"The rooftop is too far!! And the defending team's still holding their ground firmly!!","TWN":"雖然離頂樓還很遠！！而且防守方的兵力依舊！！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"그럼에도─!!","JPN":"それでも─！！","ENG":"But even with all that–!!","TWN":"雖然如此—！！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"그럼에도 카나리아는 끝까지 포기하지 않았다─!!","JPN":"それでもカナリアは最後まで諦めないつもりだ─！！","ENG":"Even when all odds are against them, Canary Squad has not given up–!!","TWN":"金絲雀還是沒有放棄—！！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"마지막 역습을 준비하는 두 사람─!!","JPN":"最後の逆転を狙う二人─！！","ENG":"The two are preparing their last attack–!!","TWN":"她們二個正在準備最後一次反擊—！！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_PRIDE"},"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"두 사람이 다시 한번 챔피언에게 닿을 수 있게─!! 다들 응원 부탁해─!!","JPN":"二人がもう一度チャンピオンに届くように！！　みんなも応援よろしくね！！","ENG":"Let's all cheer them on–!! So that they can confront the champion once more–!!","TWN":"大家一起為她們加油—！！希望她們能再一次靠近冠軍—！！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"밋치도, 미치도 여기서 응원할 테니까─!!","JPN":"ミッチーミッチーも、私も、ここで応援しているから─！！","ENG":"Mitchie-Mitchie will be cheering them on too–!!","TWN":"米琪也會在這裡替她們加油的—！！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"subtitle","speaker":null,"text":{"KOREA":"<color=#ffd34c>■■■</color> 가즈아아아아아아!!! 카나리아!!!\\n<color=#ffd34c>■ ■</color> 오지만디아스를 상대로 이렇게 잘 싸웠던 상대가 있었나?\\n<color=#ffd34c>■ ■■</color> 진짜 카나리아 스쿼드는 전설이다.\\n<color=#ffd34c>■■ ■</color> 삼등 시민이든 뭐든 그런 건 이제 상관없어.\\n<color=#ffd34c>■■ ■</color> 그냥 좀 카나리아 스쿼드가 이겼으면 좋겠어ㅋㅋㅋㅋㅋㅋ\\n<color=#ffd34c>■■ ■</color> 이 정도 되면, 그냥 너무 짠해 ㅠㅠㅠㅠㅠㅠㅠㅠ\\n<color=#ffd34c>■ ■ ■</color> 오지만디아스가 고일대로 고이긴 했지 ㅋㅋㅋㅋㅋㅋㅋ\\n<color=#ffd34c>■■■</color> 솔직히 이쯤되면 카운터인 챔피언보다 카나리아가 더 대단한 거 아님?","JPN":"<color=#ffd34c>■■■</color> 行けえええええ！！！　カナリア！！！\\n<color=#ffd34c>■ ■</color> オジマンディアス相手にここまで善戦した相手がいたか？\\n<color=#ffd34c>■ ■■</color> 本当にカナリア・スクワッドは伝説だ。\\n<color=#ffd34c>■■ ■</color> 3等市民だろうが、そんなものはもうどうでもいい。\\n<color=#ffd34c>■■ ■</color> カナリア・スクワッドに勝ってほしいｗｗｗｗ\\n<color=#ffd34c>■■ ■</color> ここまできたらむしろかわいそうじゃないか(涙)。\\n<color=#ffd34c>■ ■ ■</color> オジマンディアスもチャンピオンの座に居座りすぎたよなｗｗｗ\\n<color=#ffd34c>■■■</color> もはやこの時点になると、カウンターであるチャンピオンよりカナリアの方がすごいと言えるんじゃね？","ENG":"<color=#ffd34c>■■■</color> LET'S GOOOO!!! CANARY SQUAD!!!\\n<color=#ffd34c>■ ■</color> Was there ever a challenger who fought this well against the champion before?\\n<color=#ffd34c>■ ■■</color> Man, Canary Squad is a legend.\\n<color=#ffd34c>■■ ■</color> Who cares if they're third-grade citizens now?\\n<color=#ffd34c>■■ ■</color> I just want Canary Squad to win now. LOL!\\n<color=#ffd34c>■■ ■</color> But it's too hard to watch. I'm tearing up...\\n<color=#ffd34c>■ ■ ■</color> Ozymandias' reign lasted long enough. LMAO!\\n<color=#ffd34c>■■■</color> TBH, isn't Canary Squad far greater than the champion who's a Counter?","TWN":"<color=#ffd34c>■■■</color> 加油！！！金絲雀！！！\\n<color=#ffd34c>■ ■</color> 之前從未出現過可以和奧茲曼迪亞斯抗衡的人吧？\\n<color=#ffd34c>■ ■■</color> 金絲雀小隊超帥的！\\n<color=#ffd34c>■■ ■</color> 管他是三等市民還是什麼都好啦！\\n<color=#ffd34c>■■ ■</color> 現在只希望金絲雀小隊會贏，呵呵呵\\n<color=#ffd34c>■■ ■</color> 有點替他們心疼呢，嗚嗚嗚嗚\\n<color=#ffd34c>■ ■ ■</color> 奧茲曼迪亞斯可不好對付，呵呵呵呵\\n<color=#ffd34c>■■■</color> 老實說這樣看下來，金絲雀比制裁者冠軍還厲害吧？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"이렇게 오랜만에 우리 둘만 있으니까 그릴파티 때 생각난다, 야.","JPN":"こうして久々に二人きりになると、グリルパーティーの頃を思い出すな。","ENG":"Being just the two of us, it reminds me of when we were in Grill Party.","TWN":"好久沒有像這樣二個人獨處，讓我想起在格里爾派提的時期呢。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"그때도 사채업자 잡아 보겠다고 둘이서 쌩쇼를 했잖냐, 기억나?","JPN":"あの時も闇金業者を捕まえるって言って二人で大騒ぎしていたっけ。","ENG":"Even then, we did crazy stuff just to catch that loan shark, remember?","TWN":"那時候我們為了抓高利貸弄得手忙腳亂的，你還記得嗎？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"기억나요. 그때도 라이카 때문에 놓쳤죠.","JPN":"覚えているわ。あの時もライカのせいで取り逃したんだったわよね。","ENG":"I remember. We lost her because of you, Laika.","TWN":"當然記得，那次是你害我們沒抓到人。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"야, 그게 나 때문이냐?","JPN":"はあ、どこか私のせいだよ！","ENG":"Whoa, that's my fault?","TWN":"喂，怎麼會是我害的？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"카운터들도 순무처럼 처박혔다는데 우리가 실전에서 그걸 무슨 수로 이기겠냐?","JPN":"カウンターたちですらバタバタと倒されたっていう敵を相手に、私たちが実戦で勝てるわけがないだろ？","ENG":"How were we even supposed to win when even the Counters got stuck to the ground like turnips?","TWN":"連制裁者都被弄到倒栽蔥欸，我們怎麼可能打得贏？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"그래서 어때. 이번에는 승산이 있을 거 같아?","JPN":"それでどう、今回は勝ち目ありそう？","ENG":"So, what do you think? Do we have a shot at winning this time?","TWN":"所以，你覺得這次我們有勝算嗎？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"한 가지. 건틀렛이라, 가능한 방법이 딱 하나 있어요.","JPN":"一つだけ。ガントレットという競技だからこそできる方法があるにはあるわ。","ENG":"There is one way. A way that's only possible because it's the Gauntlet.","TWN":"有一個辦法。因為是聖鎧，所以有一個可行的辦法。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"대신 우리는 목숨을 걸어야 해요. 괜찮겠어요?","JPN":"その代わり命を賭けないといけないけど。それでもやる？","ENG":"But we'll have to risk both our lives. Are you okay with that?","TWN":"不過要賭上我們的性命，你可以嗎？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"쳇, 이거 완전 손해 보는 거래구만.","JPN":"ちっ、完全に割りに合わない仕事だな。","ENG":"Tch! So this is a total loss on my end, eh?","TWN":"嘖，完全是吃力不討好的交易欸。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"그래도 뭐 어쩌겠냐?","JPN":"でもまぁ、仕方がないか。","ENG":"But what else can I do?","TWN":"不過能怎麼辦呢？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"하류 인생 주제에 챔피언을 꺾으려면, 목숨 정도는 걸어 줘야지.","JPN":"その日暮らしの私たちがチャンピオンを倒そうと思ったら、命ぐらい賭けないとな。","ENG":"Lowlifes like us have to risk our lives to defeat the champion, right?","TWN":"三等市民想打贏冠軍的話，賭上性命是必須的吧。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"CHOWON_PERSONA_NULL_NULL","text":{"KOREA":"목숨을 걸기 전에 조언을 하나 해드리죠.","JPN":"命を賭ける前に、一つアドバイスをお伝えします。","ENG":"Before you do, allow me to give some advice.","TWN":"在你們賭上性命之前，我給你們一個建議。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L34_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"깜짝이야! 당신 리타이어 당한 거 아니었어?","JPN":"ビックリした！　あんたリタイアしたんじゃなかったの？","ENG":"Geez! I thought you were out?","TWN":"嚇我一跳！你不是已經遭到淘汰了嗎？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"CHOWON_PERSONA_NULL_NULL","text":{"KOREA":"네, 적에게 제압돼서 포로로 잡혀 있는 상태랍니다.","JPN":"はい、敵に制圧されて捕虜になっています。","ENG":"No, I'm currently taken hostage by the enemy.","TWN":"對，我被敵人抓走，現在算是俘虜狀態。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"CHOWON_PERSONA_NULL_NULL","text":{"KOREA":"절 구해주실 필요는 없어요. 도폭선을 다 써버린 저는 쓸모가 없거든요.","JPN":"私を助け出す必要はありません。導爆戦を使い切った私は役に立ちませんので。","ENG":"You don't have to come get me. I won't be of any help because I've already used up all my detonation cords.","TWN":"不需要救我，用完導火線的我已經毫無用處。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"CHOWON_PERSONA_NULL_NULL","text":{"KOREA":"하지만 지하 루트에는 아직 거미 지뢰가 몇 기 남아 있어요.","JPN":"ですが、地下ルートにはまだいくつか蜘蛛型地雷が残っています。","ENG":"However, there should be some spider mines left on the underground route.","TWN":"但地下路線還剩下幾個蜘蛛地雷。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"그렇다는 말은……?","JPN":"ということは……？","ENG":"So you're saying that...","TWN":"意思是……？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"CHOWON_PERSONA_NULL_NULL","text":{"KOREA":"지하루트로 가세요. 옥상까지 직통으로 연결된 화물 엘리베이터가 있으니까요.","JPN":"地下ルートに行ってください。屋上まで直通の貨物用エレベーターがあります。","ENG":"Take the underground route. There will be a cargo elevator that connects directly to the rooftop.","TWN":"去地下路線吧，那裡有直達頂樓的貨梯。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"CHOWON_PERSONA_NULL_NULL","text":{"KOREA":"발각될 위험이 있지만, 매설된 거미 지뢰를 이용하면 보다 유리하게 싸울 수 있을 겁니다.","JPN":"ばれる危険性はありますが、埋めておいた蜘蛛型地雷を利用すれば戦いをより有利に進められるはずです。","ENG":"There is a risk of getting detected, but you can carry out the fight to your advantage if you use the planted spider mines.","TWN":"雖然有被發現的風險，但只要妥善利用埋好的蜘蛛地雷，就可以成為你們的助力。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"하아…. 이거 마지막까지 많이도 신세 지는구만.","JPN":"はぁ……最後まで助けられちゃったな。","ENG":"*Sigh...* Guess we're getting a lot of help, even at the end.","TWN":"哈……到最後都還是受到你的照顧呢。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"이래 놓고 지면, 어디 쪽팔려서 고개 들고 살겠냐?","JPN":"これで負けたら、この先恥ずかしくて顔あげられないよ。","ENG":"How are we supposed to see their faces if we lose, right?","TWN":"這樣再輸的話，就無顏見江東父老咧。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"맞는 말이에요.","JPN":"その通りです。","ENG":"Right.","TWN":"說的沒錯。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L1_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"가요, 라이카.","JPN":"行くわよ、ライカ。","ENG":"Let's go, Laika.","TWN":"走吧，萊卡。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"다시 한 번…… 오지만디아스에게 도전하는 거예요.","JPN":"もう一度……オジマンディアスに挑むわ。","ENG":"One last time... we're going to challenge Ozymandias.","TWN":"再一次……挑戰奧茲曼迪亞斯。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};